// src/pages/FinesPage.js
import React, { useState, useEffect, useMemo } from 'react';
import { finesAPI } from '../services/api';
import { useAuth } from '../context/AuthContext';
import {
  normalizeAPIResponse,
  ensureArray,
  safeNumber,
  getFineAmount,
  normalizeStatus,
} from '../utils/apiHelpers';

// ─────────────────────────────────────────────────────────────
// CONSTANTS
// ─────────────────────────────────────────────────────────────
const STATUS_OPTIONS = ['All', 'Unpaid', 'Paid', 'Waived'];

// ─────────────────────────────────────────────────────────────
// SUB-COMPONENTS
// ─────────────────────────────────────────────────────────────
const StatCard = ({ icon, color, value, label }) => (
  <div className="col-sm-6 col-lg-3">
    <div className="stat-card">
      <div className={`stat-icon ${color}`}>
        <i className={`bi ${icon}`}></i>
      </div>
      <div>
        <div className="stat-value">{value}</div>
        <div className="stat-label">{label}</div>
      </div>
    </div>
  </div>
);

// ─────────────────────────────────────────────────────────────
// MAIN COMPONENT
// ─────────────────────────────────────────────────────────────
const FinesPage = () => {
  const { currentUser } = useAuth();
  const role = currentUser?.role;

  const [fines,         setFines]         = useState([]);
  const [searchQuery,   setSearchQuery]   = useState('');
  const [statusFilter,  setStatusFilter]  = useState('All');
  const [loading,       setLoading]       = useState(true);
  const [error,         setError]         = useState(null);
  const [payingId,      setPayingId]      = useState(null);

  // ── Fetch ─────────────────────────────────────────────────
  const fetchFines = async () => {
    setLoading(true);
    setError(null);
    try {
      const res = role === 'Student'
        ? await finesAPI.getMyFines()
        : await finesAPI.getAll();

      setFines(ensureArray(normalizeAPIResponse(res)));
    } catch (err) {
      console.error('FinesPage fetch error:', err);
      setError('Failed to load fines. Please try again.');
      setFines([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (role) fetchFines();
  }, [role]);

  // ── Derived / filtered data (memoised) ────────────────────
  const { filtered, totalFine, unpaidFine, paidFine } = useMemo(() => {
    const baseFines = ensureArray(fines);

    const filtered = baseFines.filter((f) => {
      if (!f) return false;

      // Status filter
      if (statusFilter !== 'All' &&
          normalizeStatus(f.status) !== normalizeStatus(statusFilter)) {
        return false;
      }

      // Search filter — check student name or book title
      if (searchQuery.trim()) {
        const q = searchQuery.trim().toLowerCase();
        const studentName = (f.student?.name ?? f.studentName ?? '').toLowerCase();
        const bookTitle   = (f.book?.title   ?? f.bookTitle   ?? '').toLowerCase();
        if (!studentName.includes(q) && !bookTitle.includes(q)) return false;
      }

      return true;
    });

    const safeFiltered = ensureArray(filtered);

    const totalFine = safeFiltered.reduce(
      (sum, f) => sum + getFineAmount(f),
      0
    );

    const unpaidFine = safeFiltered
      .filter((f) => f && normalizeStatus(f.status) === 'unpaid')
      .reduce((sum, f) => sum + getFineAmount(f), 0);

    const paidFine = safeFiltered
      .filter((f) => f && normalizeStatus(f.status) === 'paid')
      .reduce((sum, f) => sum + getFineAmount(f), 0);

    return { filtered: safeFiltered, totalFine, unpaidFine, paidFine };
  }, [fines, statusFilter, searchQuery]);

  // ── Mark as paid ──────────────────────────────────────────
  const handleMarkPaid = async (id) => {
    setPayingId(id);
    const fine = fines.find(f => f._id === id);
    const amount = getFineAmount(fine);

    try {
      await finesAPI.pay(id, { amount, paymentMethod: 'Cash' });
      setFines((prev) =>
        ensureArray(prev).map((f) =>
          f._id === id ? { ...f, status: 'Paid' } : f
        )
      );
    } catch (err) {
      alert(err?.message ?? 'Could not mark fine as paid.');
    } finally {
      setPayingId(null);
    }
  };

  // ── Render ────────────────────────────────────────────────
  if (loading)
    return (
      <div className="text-center py-5">
        <div className="spinner-border text-primary"></div>
        <p className="mt-2 text-muted">Loading fines…</p>
      </div>
    );

  if (error)
    return (
      <div className="text-center py-5">
        <p className="text-danger">{error}</p>
        <button className="btn btn-lib-primary mt-2" onClick={fetchFines}>
          Retry
        </button>
      </div>
    );

  return (
    <div className="page-wrapper">
      <div className="container">

        {/* Header */}
        <div className="mb-4">
          <h2 className="section-title">
            <i className="bi bi-currency-rupee me-2"></i>
            {role === 'Student' ? 'My Fines' : 'All Fines'}
          </h2>
          <p className="text-muted" style={{ fontSize: '.9rem' }}>
            {role === 'Student'
              ? 'Track and pay your library fines here.'
              : 'Manage fines for all students.'}
          </p>
        </div>

        {/* Stats */}
        <div className="row g-3 mb-4">
          <StatCard
            icon="bi-list-ul"
            color="blue"
            value={filtered.length}
            label="Total Records"
          />
          <StatCard
            icon="bi-currency-rupee"
            color="red"
            value={`₹${safeNumber(totalFine)}`}
            label="Total Amount"
          />
          <StatCard
            icon="bi-exclamation-circle"
            color="gold"
            value={`₹${safeNumber(unpaidFine)}`}
            label="Unpaid"
          />
          <StatCard
            icon="bi-check-circle"
            color="green"
            value={`₹${safeNumber(paidFine)}`}
            label="Paid"
          />
        </div>

        {/* Filters */}
        <div className="lib-card mb-4 p-3">
          <div className="row g-3 align-items-end">
            <div className="col-md-6">
              <label className="form-label fw-semibold" style={{ fontSize: '.85rem' }}>
                Search
              </label>
              <div className="input-group">
                <span className="input-group-text">
                  <i className="bi bi-search"></i>
                </span>
                <input
                  type="text"
                  className="form-control"
                  placeholder="Search by student or book…"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
                {searchQuery && (
                  <button
                    className="btn btn-outline-secondary"
                    onClick={() => setSearchQuery('')}
                  >
                    <i className="bi bi-x"></i>
                  </button>
                )}
              </div>
            </div>
            <div className="col-md-3">
              <label className="form-label fw-semibold" style={{ fontSize: '.85rem' }}>
                Status
              </label>
              <select
                className="form-select"
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
              >
                {STATUS_OPTIONS.map((s) => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
            <div className="col-md-3">
              <button
                className="btn btn-lib-secondary w-100"
                onClick={() => { setSearchQuery(''); setStatusFilter('All'); }}
              >
                <i className="bi bi-arrow-counterclockwise me-1"></i>Reset
              </button>
            </div>
          </div>
        </div>

        {/* Table */}
        <div className="lib-card">
          <div className="lib-card-header">
            <h5>
              <i className="bi bi-table me-2"></i>
              Fine Records
              <span className="text-muted ms-2" style={{ fontSize: '.8rem', fontWeight: 400 }}>
                ({filtered.length} record{filtered.length !== 1 ? 's' : ''})
              </span>
            </h5>
          </div>
          <div className="table-responsive">
            <table className="lib-table">
              <thead>
                <tr>
                  <th>#</th>
                  {role !== 'Student' && <th>Student</th>}
                  <th>Book</th>
                  <th>Amount</th>
                  <th>Issue Date</th>
                  <th>Due Date</th>
                  <th>Status</th>
                  {role !== 'Student' && <th>Action</th>}
                </tr>
              </thead>
              <tbody>
                {filtered.length === 0 ? (
                  <tr>
                    <td
                      colSpan={role !== 'Student' ? 8 : 6}
                      className="text-center text-muted py-4"
                    >
                      No fine records found
                      {statusFilter !== 'All' && ` for status "${statusFilter}"`}.
                    </td>
                  </tr>
                ) : (
                  filtered.map((f, i) => (
                    <tr key={f._id ?? i}>
                      <td>{i + 1}</td>
                      {role !== 'Student' && (
                        <td>{f.student?.name ?? f.studentName ?? 'N/A'}</td>
                      )}
                      <td>{f.book?.title ?? f.bookTitle ?? 'N/A'}</td>
                      <td>₹{safeNumber(getFineAmount(f))}</td>
                      <td>
                        {f.issueDate
                          ? new Date(f.issueDate).toLocaleDateString()
                          : 'N/A'}
                      </td>
                      <td>
                        {f.dueDate
                          ? new Date(f.dueDate).toLocaleDateString()
                          : 'N/A'}
                      </td>
                      <td>
                        <span
                          className={`badge-role badge-${normalizeStatus(f.status)}`}
                        >
                          {f.status ?? 'Unknown'}
                        </span>
                      </td>
                      {role !== 'Student' && (
                        <td>
                          {normalizeStatus(f.status) === 'unpaid' && (
                            <button
                              className="btn btn-sm btn-lib-primary"
                              disabled={payingId === f._id}
                              onClick={() => handleMarkPaid(f._id)}
                            >
                              {payingId === f._id
                                ? <span className="spinner-border spinner-border-sm"></span>
                                : 'Mark Paid'}
                            </button>
                          )}
                        </td>
                      )}
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </div>

      </div>
    </div>
  );
};

export default FinesPage;
